@app.route('/profile', methods=['PUT'])
@login_required
def update_profile():
    data = request.get_json()
    if not data:
        return jsonify({'message': 'No data provided for update'}), 400

    updatable_fields = [
        'email', 'username', 'account_type', 'credits', 'referral_code', 'verified_status'
    ]
    updated_fields = {}

    for field in updatable_fields:
        if field in data:
            # Basic validation/type conversion for specific fields
            if field == 'email':
                if not isinstance(data[field], str) or '@' not in data[field]:
                    return jsonify({'message': f'Invalid {field} format'}), 400
            elif field == 'username':
                if not isinstance(data[field], str) or not data[field].strip():
                    return jsonify({'message': f'Invalid {field}'}), 400
            elif field == 'account_type':
                allowed_types = ['free', 'premium', 'enterprise'] # Define your allowed account types
                if data[field] not in allowed_types:
                    return jsonify({'message': f'Invalid {field}. Must be one of {", ".join(allowed_types)}'}), 400
            elif field == 'credits':
                try:
                    data[field] = int(data[field])
                    if data[field] < 0:
                        raise ValueError("Credits cannot be negative")
                except (ValueError, TypeError):
                    return jsonify({'message': f'Invalid {field}. Must be a non-negative integer'}), 400
            elif field == 'verified_status':
                if not isinstance(data[field], bool):
                    return jsonify({'message': f'Invalid {field}. Must be a boolean'}), 400
            # referral_code can be string or None
            elif field == 'referral_code' and data[field] is not None:
                if not isinstance(data[field], str):
                    return jsonify({'message': f'Invalid {field}. Must be a string or null'}), 400

            # Update the user object dynamically
            setattr(current_user, field, data[field])
            updated_fields[field] = data[field]

    if not updated_fields:
        return jsonify({'message': 'No valid fields provided for update'}), 400

    # In a real application, you would save current_user to your database here
    # Example: db.session.commit() if using SQLAlchemy

    return jsonify({
        'message': 'Profile updated successfully',
        'updated_fields': updated_fields,
        'new_profile': current_user.to_dict()
    }), 200


